def get_all_t20_players(gender=None, include_u19=True):
    players = list(T20_PLAYERS)
    
    if include_u19:
        from u19_players import get_all_u19_players
        u19 = get_all_u19_players()
        existing_names = {p["name"].lower() for p in players}
        for p in u19:
            if p["name"].lower() not in existing_names:
                players.append(p)
    
    if gender == "women":
        return [p for p in players if p.get("gender") == "women"]
    elif gender == "men":
        return [p for p in players if p.get("gender") != "women"]
    return players

def get_t20_batsmen(gender=None):
    players = get_all_t20_players(gender)
    return [p for p in players if "Batsman" in p["role"] or "All-rounder" in p["role"]]

def get_t20_bowlers(gender=None):
    players = get_all_t20_players(gender)
    return [p for p in players if "Bowler" in p["role"] or "All-rounder" in p["role"]]

def search_t20_players(query, gender=None):
    query = query.lower()
    players = get_all_t20_players(gender)
    return [p for p in players if query in p["name"].lower() or query in p["country"].lower()]

def get_player_by_name(name):
    for player in T20_PLAYERS:
        if player["name"].lower() == name.lower():
            return player
    return None

def get_discovered_players_from_db():
    """Get all discovered players from the database"""
    try:
        from models import DiscoveredPlayer
        discovered = DiscoveredPlayer.query.all()
        return [p.to_dict() for p in discovered]
    except Exception:
        return []

def get_all_players_including_discovered(gender=None):
    """Get all local players plus discovered players from database"""
    local_players = get_all_t20_players(gender)
    local_names = {p["name"].lower() for p in local_players}
    
    discovered = get_discovered_players_from_db()
    for player in discovered:
        if player["name"].lower() not in local_names:
            local_players.append(player)
    
    return local_players
